import { useRouter } from 'next/router'
import { useEffect, useState } from 'react'

type Section = { id: string; title: string; content: string; order: number }
type Detail = {
  id: string
  title: string
  sourceName: string | null
  sourceUrl: string | null
  verificationBadge: string
  sections: Section[]
}

export default function ReferenceDetailPage() {
  const router = useRouter()
  const { id } = router.query
  const [data, setData] = useState<Detail | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!id) return
    setLoading(true)
    fetch(`/api/references/${id}`)
      .then((r) => (r.ok ? r.json() : Promise.reject(new Error('reference not found'))))
      .then((d) => setData(d))
      .catch((e: Error) => setError(e.message))
      .finally(() => setLoading(false))
  }, [id])

  if (loading) return <main className="p-6">Loading...</main>
  if (error || !data) return <main className="p-6 text-red-700">{error || 'Not found'}</main>

  return (
    <main className="mx-auto max-w-5xl px-6 py-10">
      <h1 className="text-3xl font-bold">{data.title}</h1>
      <div className="mt-2 text-sm text-gray-600">
        <span>{data.sourceName || 'Unknown source'}</span>
        {data.sourceUrl ? <a className="ml-3 underline" href={data.sourceUrl} target="_blank" rel="noreferrer">Source</a> : null}
      </div>
      <p className="mt-1 text-xs text-green-700">{data.verificationBadge}</p>

      <section className="mt-8 space-y-6">
        {data.sections.map((s) => (
          <article key={s.id}>
            <h2 className="mb-2 text-xl font-semibold">{s.title}</h2>
            <p className="whitespace-pre-wrap text-gray-800">{s.content}</p>
          </article>
        ))}
      </section>
    </main>
  )
}
